-- Cupboard Support: dashboard simulation data (Phase 4)
-- Run this in the Supabase SQL Editor.
--
-- Generates ~420 simulated conversations over the past 30 days with
-- realistic distributions (intent mix, deflection rates, escalation
-- reasons). All rows are tagged with metadata.simulated = true so
-- they can be cleanly deleted and regenerated.

-- Wipe any prior simulation data
delete from analytics_events where (metadata->>'simulated')::boolean = true;
delete from messages where conversation_id in (
  select id from conversations where resolution_summary = 'simulated'
);
delete from conversations where resolution_summary = 'simulated';

-- Conversations

-- Analytics events

-- Verify
select count(*) as conversations from conversations where resolution_summary = 'simulated';
select count(*) as events from analytics_events where (metadata->>'simulated')::boolean = true;
